const PARENT_SUMMARIES = {"onboarding": "Understand the operator onboarding experience, prepare for facilitated sessions and connect each onboarding activity to configuration, testing and launch.", "decisions": "Define and track the business, policy and operating decisions that shape platform configuration and marketplace processes.", "foundations": "Learn how the operator, sellers, storefront, payments and connected systems work together in a multi-seller marketplace.", "setup": "Configure the environments, access, branding, communications and foundational settings required before seller onboarding and launch.", "finance": "Understand commercial models, commission, wholesale, tax, payments, remittance and financial operating responsibilities.", "structure": "Design the taxonomy, prototypes, attributes, categories and brands that govern seller product data.", "seller": "Plan, create, onboard, train and manage sellers from initial prospect through launch and ongoing performance.", "product": "Ingest, map, approve and maintain seller products while protecting catalogue consistency and quality.", "orders": "Configure shipping and understand how marketplace orders are split, dispatched, tracked and handled when exceptions occur.", "refunds": "Configure and operate pre-dispatch cancellations, post-dispatch returns, refunds and their financial effects.", "reporting": "Use operational, seller, catalogue, sales and finance information to manage the marketplace after launch.", "integrations": "Understand data ownership and the integrations that connect the storefront, Marketplacer, sellers, payments and fulfilment.", "testing": "Validate configuration and end-to-end scenarios before launch, then monitor the first live marketplace transactions.", "resources": "Find operator templates, training resources, seller guidance and the information needed to request Marketplacer Support."};

const root = document.getElementById("page-root");
const navigationRoot = document.getElementById("primary-navigation");
const sidebar = document.getElementById("sidebar");
const menuButton = document.getElementById("mobile-menu-button");
const backdrop = document.getElementById("drawer-backdrop");
const backToTop = document.getElementById("back-to-top");

const slugify = value => value
  .toLowerCase()
  .replace(/&/g, "and")
  .replace(/[^a-z0-9]+/g, "-")
  .replace(/(^-|-$)/g, "");

const currentPageId = () => new URLSearchParams(window.location.search).get("page") || "home";

const flatPages = NAVIGATION.flatMap(parent =>
  parent.children.map(child => ({ ...child, parentId: parent.id, parentTitle: parent.title.replace(/^\d+\.\s*/, "") }))
);

const findPage = id => flatPages.find(page => page.id === id);
const findParent = id => NAVIGATION.find(parent => parent.id === id);

function pageHref(id, section = "") {
  const suffix = section ? `#${slugify(section)}` : "";
  return `?page=${encodeURIComponent(id)}${suffix}`;
}

function renderNavigation() {
  const pageId = currentPageId();
  const activePage = findPage(pageId);
  let html = `<a class="nav-home ${pageId === "home" ? "active" : ""}" href="index.html">Home</a>`;

  NAVIGATION.forEach(parent => {
    const isOpen = activePage?.parentId === parent.id;
    html += `
      <section class="nav-section ${isOpen ? "open active-parent" : ""}" data-parent="${parent.id}">
        <button class="nav-section-toggle" aria-expanded="${isOpen}">
          <span class="nav-section-label">
            <span class="nav-section-number" aria-hidden="true">${parent.title.match(/^\d+/)?.[0] || ""}</span>
            <span class="nav-section-title">${parent.title.replace(/^\d+\.\s*/, "")}</span>
          </span>
          <svg viewBox="0 0 24 24" aria-hidden="true"><path d="m7 9 5 5 5-5"/></svg>
        </button>
        <div class="nav-children">
          ${parent.children.map(child => `
            <a class="nav-child ${child.id === pageId ? "active" : ""}" href="${pageHref(child.id)}">${child.title}</a>
          `).join("")}
        </div>
      </section>
    `;
  });

  navigationRoot.innerHTML = html;

  navigationRoot.querySelectorAll(".nav-section-toggle").forEach(button => {
    button.addEventListener("click", () => {
      const section = button.closest(".nav-section");
      const opening = !section.classList.contains("open");
      section.classList.toggle("open", opening);
      button.setAttribute("aria-expanded", String(opening));
    });
  });
}


