function buildToc(page, sections) {
  return `
    <aside class="on-page-toc" aria-label="On this page">
      <h2>On this page</h2>
      <nav>
        ${sections.map(section => `<a href="${pageHref(page.id, section)}" data-section="${slugify(section)}">${section}</a>`).join("")}
      </nav>
    </aside>
  `;
}

function buildBreadcrumbs(page) {
  return `
    <nav class="breadcrumbs" aria-label="Breadcrumb">
      <a href="index.html">Home</a>
      <span class="breadcrumb-separator">/</span>
      <span>${page.parentTitle}</span>
      <span class="breadcrumb-separator">/</span>
      <span aria-current="page">${page.title}</span>
    </nav>
  `;
}

function buildPager(page) {
  const index = flatPages.findIndex(item => item.id === page.id);
  const previous = index > 0 ? flatPages[index - 1] : null;
  const next = index < flatPages.length - 1 ? flatPages[index + 1] : null;
  return `
    <nav class="pager" aria-label="Previous and next topics">
      ${previous ? `<a class="pager-link" href="${pageHref(previous.id)}"><span>Previous topic</span><strong>${previous.title}</strong></a>` : `<span></span>`}
      ${next ? `<a class="pager-link next" href="${pageHref(next.id)}"><span>Next topic</span><strong>${next.title}</strong></a>` : `<span></span>`}
    </nav>
  `;
}

function buildRelated(related = []) {
  if (!related.length) return "";
  return `
    <div>
      <h2 class="related-title">Related topics</h2>
      <div class="related-links">
        ${related.map(([id, title]) => `<a class="related-link" href="${pageHref(id)}">${title}</a>`).join("")}
      </div>
    </div>
  `;
}

function enhanceMarketplacerArticlePanels() {
  document.querySelectorAll(".content-section h3").forEach(heading => {
    const title = heading.textContent.trim();
    if (!/^Related Marketplacer articles?$/i.test(title)) return;

    const list = heading.nextElementSibling;
    if (!list || list.tagName !== "UL") return;

    const panel = document.createElement("aside");
    panel.className = "marketplacer-articles";
    panel.setAttribute("aria-label", "Related Marketplacer articles");

    const eyebrow = document.createElement("p");
    eyebrow.className = "marketplacer-articles-eyebrow";
    eyebrow.textContent = "Marketplacer resources";

    heading.parentNode.insertBefore(panel, heading);
    panel.append(eyebrow, heading, list);

    list.classList.remove(
      "check-list",
      "link-list",
      "bullet-list",
      "criteria-list",
      "compact-list"
    );
    list.classList.add("article-link-list");
  });
}

function renderPage() {
  const id = currentPageId();
  if (id === "home") {
    renderHome();
    return;
  }

  const page = findPage(id);
  if (!page) {
    window.history.replaceState({}, "", "index.html");
    renderHome();
    return;
  }

  document.title = `${page.title} | Marketplacer Operator Onboarding Hub`;
  const fullContent = PAGE_CONTENT[id];
  const parent = findParent(page.parentId);
  const summary = fullContent?.summary || PARENT_SUMMARIES[parent.id];
  const audience = fullContent?.audience || ["Operator team"];
  const sections = page.sections;
  const contentSections = sections.map(section => {
    const body = fullContent?.sections?.[section] || `
      <div class="placeholder-panel">
        <h2>Content planned</h2>
        <p>This section is included to validate the approved information architecture. Detailed operator guidance will be developed after the prototype layout and navigation have been reviewed.</p>
      </div>
    `;
    return `<section class="content-section" id="${slugify(section)}"><h2>${section}</h2>${body}</section>`;
  }).join("");

  root.innerHTML = `
    <div class="page-frame">
      <article class="page-column">
        ${buildBreadcrumbs(page)}
        <header class="page-header ${PAGE_ILLUSTRATIONS[page.id] ? "has-illustration" : ""}">
          <div class="page-header-copy">
            <p class="page-kicker">${page.parentTitle}</p>
            <h1>${page.title}</h1>
            <p class="page-summary">${summary}</p>
            <div class="meta-row">
              ${audience.map(item => `<span class="meta-chip">${item}</span>`).join("")}
              <span class="meta-chip">${fullContent ? "Operator guidance" : "Content placeholder"}</span>
            </div>
          </div>
          ${PAGE_ILLUSTRATIONS[page.id] ? `<img class="page-header-illustration" src="${PAGE_ILLUSTRATIONS[page.id].src}" alt="${PAGE_ILLUSTRATIONS[page.id].alt}">` : ""}
        </header>
        <div class="page-body">${contentSections}</div>
        <footer class="page-footer">
          ${buildRelated(fullContent?.related)}
          ${buildPager(page)}
        </footer>
      </article>
      ${buildToc(page, sections)}
    </div>
  `;

  enhanceMarketplacerArticlePanels();
  setupTocObserver();
  scrollToRequestedSection();
}

function setupTocObserver() {
  const links = [...document.querySelectorAll(".on-page-toc a")];
  const sections = [...document.querySelectorAll(".content-section")];
  if (!links.length || !sections.length) return;

  const observer = new IntersectionObserver(entries => {
    const visible = entries
      .filter(entry => entry.isIntersecting)
      .sort((a, b) => a.boundingClientRect.top - b.boundingClientRect.top)[0];

    if (!visible) return;
    links.forEach(link => link.classList.toggle("active", link.dataset.section === visible.target.id));
  }, {
    rootMargin: `-${parseInt(getComputedStyle(document.documentElement).getPropertyValue("--topbar-height")) + 24}px 0px -68% 0px`,
    threshold: [0, .1]
  });

  sections.forEach(section => observer.observe(section));
}

function scrollToRequestedSection() {
  if (!window.location.hash) {
    window.scrollTo(0, 0);
    return;
  }
  const target = document.querySelector(window.location.hash);
  if (target) {
    requestAnimationFrame(() => target.scrollIntoView({ behavior: "instant", block: "start" }));
  }
}

function closeDrawer() {
  document.body.classList.remove("drawer-open");
  menuButton.setAttribute("aria-expanded", "false");
}

menuButton.addEventListener("click", () => {
  const opening = !document.body.classList.contains("drawer-open");
  document.body.classList.toggle("drawer-open", opening);
  menuButton.setAttribute("aria-expanded", String(opening));
});

backdrop.addEventListener("click", closeDrawer);
navigationRoot.addEventListener("click", event => {
  if (event.target.closest("a") && window.innerWidth <= 940) closeDrawer();
});

window.addEventListener("scroll", () => {
  backToTop.classList.toggle("visible", window.scrollY > 600);
});

backToTop.addEventListener("click", () => window.scrollTo({ top: 0, behavior: "smooth" }));

window.addEventListener("hashchange", () => {
  const target = document.querySelector(window.location.hash);
  if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
});

renderNavigation();
renderPage();
